sql:
SELECT MAX(airport_count) AS max_airport_count
FROM (
  SELECT COUNT(*) AS airport_count
  FROM airports
  GROUP BY country
) AS country_airport_counts;

external_knowledge:
- "highest-standing airports" refers to the airports ranked highest within their regions based on latitude and longitude;
- "celestial coordinates" are the latitude and longitude of the airports;
- "unattended" and "devoid of any service" mean that the airports have no recorded services.

sql:
SELECT airport_name, country
FROM airports
ORDER BY country ASC;

external_knowledge:
